import { redirect } from "next/navigation";
import { headers } from "next/headers";
import { auth } from "@/lib/auth";
import Link from "next/link";
import { 
  LayoutDashboard, 
  Truck, 
  Users, 
  Map, 
  Wrench, 
  Receipt, 
  LineChart, 
  Settings,
  LogOut,
  Menu
} from "lucide-react";
import { Button } from "@/components/ui/button";

const navItems = [
  { name: "Dashboard", href: "/", icon: LayoutDashboard },
  { name: "Fleet", href: "/fleet", icon: Truck },
  { name: "Drivers", href: "/drivers", icon: Users },
  { name: "Trips", href: "/trips", icon: Map },
  { name: "Maintenance", href: "/maintenance", icon: Wrench },
  { name: "Expenses", href: "/expenses", icon: Receipt },
  { name: "Analytics", href: "/analytics", icon: LineChart },
  { name: "Settings", href: "/settings", icon: Settings },
];

export default async function DashboardLayout({
  children,
}: {
  children: React.ReactNode;
}) {
  const session = await auth.api.getSession({
    headers: await headers(),
  });

  if (!session) {
    redirect("/login");
  }

  return (
    <div className="flex min-h-screen bg-background">
      {/* Sidebar */}
      <aside className="fixed inset-y-0 left-0 z-50 hidden w-64 flex-col bg-sidebar text-sidebar-foreground transition-all duration-300 md:flex">
        <div className="flex h-16 shrink-0 items-center justify-center border-b border-sidebar-border/50 px-6">
          <div className="flex items-center gap-2 font-bold text-2xl tracking-tight">
            <span className="text-primary">▣</span>
            TransitOps
          </div>
        </div>
        
        <nav className="flex-1 space-y-1 p-4 overflow-y-auto mt-4">
          {navItems.map((item) => {
            const Icon = item.icon;
            // For now, no strict active state logic based on path, just base style
            return (
              <Link
                key={item.name}
                href={item.href}
                className="group flex items-center gap-4 rounded-md px-4 py-3 text-sm font-medium text-sidebar-foreground/80 transition-all hover:bg-sidebar-accent hover:text-sidebar-accent-foreground"
              >
                <Icon className="h-5 w-5 text-sidebar-foreground/60 group-hover:text-primary transition-colors" />
                {item.name}
              </Link>
            );
          })}
        </nav>
        
        <div className="p-4">
          <div className="rounded-lg bg-sidebar-accent/50 p-4">
            <div className="flex items-center gap-3">
              <div className="flex h-10 w-10 items-center justify-center rounded-full bg-primary text-primary-foreground font-bold uppercase shadow-sm">
                {session.user.name?.charAt(0) || "U"}
              </div>
              <div className="flex flex-col">
                <span className="text-sm font-semibold text-sidebar-foreground">{session.user.name}</span>
                {/* @ts-ignore */}
                <span className="text-xs text-sidebar-foreground/60">{session.user.role || "Administrator"}</span>
              </div>
            </div>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 md:pl-64 flex flex-col min-h-screen">
        {/* Top Header */}
        <header className="sticky top-0 z-40 flex h-16 shrink-0 items-center justify-between border-b bg-card px-4 shadow-sm md:px-8">
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" className="md:hidden">
              <Menu className="h-5 w-5" />
            </Button>
            {/* Breadcrumb Placeholder */}
            <div className="hidden md:flex items-center text-sm text-muted-foreground font-medium">
              Dashboard <span className="mx-2">/</span> Overview
            </div>
          </div>
          <div className="flex items-center gap-4">
            <Button variant="ghost" size="icon" className="text-muted-foreground rounded-full hover:bg-muted">
              <LogOut className="h-5 w-5" />
            </Button>
          </div>
        </header>

        <div className="p-4 md:p-8 flex-1">
          {children}
        </div>
      </main>
    </div>
  );
}
